-                        defer memory.wasm_allocator.free(i32_buf);
-                        _ = frag.fragmentReadInt32(col.fragment_col_idx, i32_buf.ptr, to_read, 0);
-                        for (i32_buf, 0..) |v, j| buf[buf_idx + j] = v;
